#include <iostream>
#include <vector>
#include <sstream>

using namespace std;

class Solution {
public:
	bool solve(vector<int>& nums) {
		vector<int> result;
		result.push_back(nums[0]);
		int lastSeen = nums[0];
		for (const auto& num : nums) {
			if (num != lastSeen) {
				result.push_back(num);
				lastSeen = num;
			}
		}
		return true;
	}
};

int main() {
	int n;
	cin >> n;
	int a;
	vector<int> nums;
	for (int i = 0; i < n; i++) {
		cin >> a;
		nums.push_back(a);
	}
	Solution().solve(nums);
	return 0;
}
